'use strict';

const chai = require('chai');
const chaiAsPromised = require('chai-as-promised');
const sinon = require('sinon');

const expect = chai.expect;
chai.use(chaiAsPromised);

const AbstractProvisioningCache = require('../src/abstract-provisioning-cache');

function makeToken(payload) {
	const header = Buffer.from(JSON.stringify({ alg: 'HS256', typ: 'JWT' })).toString('base64url');
	const body = Buffer.from(JSON.stringify(payload)).toString('base64url');
	return `${header}.${body}.fakesig`;
}

class ConcreteCache extends AbstractProvisioningCache {
	constructor() {
		super();
		this._store = new Map();
	}
	async _get(key) {
		const val = this._store.get(key);
		if (val === undefined) {
			throw new Error('not found');
		}
		return val;
	}
	async _set(key, value) {
		this._store.set(key, value);
	}
}

describe('AbstractProvisioningCache', function() {
	const nowSecs = Math.round(Date.now() / 1000);
	// exp must be at least EXPIRY_BUFFER_TIME_SECONDS (120s) in the future
	const futureExp = nowSecs + 3600;
	const pastExp = nowSecs - 1;

	describe('get', function() {
		it('should throw when "claims" is not an object', function() {
			const cache = new AbstractProvisioningCache();
			return expect(cache.get(42, 'scope')).to.be.rejectedWith('"claims" must be an Object');
		});

		it('should throw when "scope" is not a string', function() {
			const cache = new AbstractProvisioningCache();
			return expect(cache.get({}, 42)).to.be.rejectedWith('"scope" must be a String');
		});

		it('should throw ValueLookupFailed when no _get is defined', function() {
			const cache = new AbstractProvisioningCache();
			return expect(cache.get({}, 'scope')).to.be.rejected;
		});

		it('should throw ValueLookupFailed when _get throws', function() {
			const cache = new ConcreteCache();
			// key not in store, so _get throws
			return expect(cache.get({}, 'scope')).to.be.rejected;
		});

		it('should throw ValueLookupFailed when _get returns a non-string', function() {
			const cache = new ConcreteCache();
			cache._get = async () => null;
			return expect(cache.get({}, 'scope')).to.be.rejected;
		});

		it('should throw ValueLookupFailed when token is not a valid JWT', async function() {
			const cache = new ConcreteCache();
			cache._get = async () => 'not-a-jwt';
			return expect(cache.get({}, 'scope')).to.be.rejected;
		});

		it('should throw ValueLookupFailed when token is expired', async function() {
			const cache = new ConcreteCache();
			cache._get = async () => makeToken({ exp: pastExp });
			return expect(cache.get({}, 'scope')).to.be.rejected;
		});

		it('should return token when valid and not expired', async function() {
			const cache = new ConcreteCache();
			const token = makeToken({ exp: futureExp });
			cache._get = async () => token;
			const result = await cache.get({}, 'scope');
			expect(result).to.equal(token);
		});

		it('should build cache key from claims and scope', async function() {
			const cache = new ConcreteCache();
			const token = makeToken({ exp: futureExp });
			let capturedKey;
			cache._get = async (key) => {
				capturedKey = key;
				return token;
			};
			await cache.get({ sub: 'user1', tenantid: 'tenant1' }, 'my:scope');
			expect(capturedKey).to.include('sub=user1');
			expect(capturedKey).to.include('scope=my%3Ascope');
		});
	});

	describe('set', function() {
		it('should throw when "claims" is not an object', function() {
			const cache = new AbstractProvisioningCache();
			return expect(cache.set(42, 'scope', makeToken({ exp: futureExp }))).to.be.rejectedWith('"claims" must be an Object');
		});

		it('should throw when "scope" is not a string', function() {
			const cache = new AbstractProvisioningCache();
			return expect(cache.set({}, 42, makeToken({ exp: futureExp }))).to.be.rejectedWith('"scope" must be a String');
		});

		it('should throw when "token" is not a string', function() {
			const cache = new AbstractProvisioningCache();
			return expect(cache.set({}, 'scope', null)).to.be.rejectedWith('"token" must be an encoded jwt');
		});

		it('should throw when "token" is not a valid JWT', function() {
			const cache = new AbstractProvisioningCache();
			return expect(cache.set({}, 'scope', 'not-a-jwt')).to.be.rejectedWith('"token" must be an encoded jwt');
		});

		it('should succeed without calling _set when no _set defined', async function() {
			const cache = new AbstractProvisioningCache();
			const token = makeToken({ exp: futureExp });
			await cache.set({}, 'scope', token);
		});

		it('should call _set with key, token and computed expiry', async function() {
			const cache = new ConcreteCache();
			const setSpy = sinon.spy(cache, '_set');
			const token = makeToken({ exp: futureExp });
			await cache.set({ sub: 'user1' }, 'my:scope', token);
			expect(setSpy.calledOnce).to.be.true;
			const [key, storedToken, expiry] = setSpy.firstCall.args;
			expect(key).to.be.a('string').and.include('sub=user1');
			expect(storedToken).to.equal(token);
			// expiry = exp - EXPIRY_BUFFER_TIME_SECONDS (120)
			expect(expiry).to.equal(futureExp - 120);
		});

		it('should use default expiry when token has no exp claim', async function() {
			const cache = new ConcreteCache();
			const setSpy = sinon.spy(cache, '_set');
			const token = makeToken({});
			await cache.set({}, 'scope', token);
			const [, , expiry] = setSpy.firstCall.args;
			const expectedMin = Math.round(Date.now() / 1000) + 3600 - 120 - 2;
			const expectedMax = Math.round(Date.now() / 1000) + 3600 - 120 + 2;
			expect(expiry).to.be.within(expectedMin, expectedMax);
		});
	});
});
